import{_ as n,c as a,a1 as i,o as t}from"./chunks/framework.BDxlaA_J.js";const g=JSON.parse('{"title":"Enumerate Dịch vụ","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/3-enumeration/1-Enumerating-with-Nmap.md","filePath":"vi/categories/ethical-hacking-labs/3-enumeration/1-Enumerating-with-Nmap.md"}'),p={name:"vi/categories/ethical-hacking-labs/3-enumeration/1-Enumerating-with-Nmap.md"};function e(h,s,l,c,o,r){return t(),a("div",null,s[0]||(s[0]=[i(`<h1 id="enumerate-dich-vu" tabindex="-1">Enumerate Dịch vụ <a class="header-anchor" href="#enumerate-dich-vu" aria-label="Permalink to &quot;Enumerate Dịch vụ&quot;">​</a></h1><p>Trích xuất tên người dùng, tên máy, tài nguyên mạng, shares và dịch vụ từ một hệ thống.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Quét tất cả các máy trong một mạng hoặc subnet nhất định.</li><li>Liệt kê tất cả các host đang hoạt động.</li><li>Xác định các cổng mở trên một node nhất định.</li><li>Kiểm tra xem có cổng nào bị giới hạn bởi firewall hay không.</li><li>Enumerate tất cả các dịch vụ đang chạy trên cổng cùng với phiên bản tương ứng.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy Windows Server 2012 hoặc 2016.</li><li>Máy Kali Linux.</li><li>Một phiên bản Windows khác (7, 8, 10 hoặc Server).</li></ul><h2 id="ping-sweep-nmap" tabindex="-1">Ping Sweep - <code>Nmap</code> <a class="header-anchor" href="#ping-sweep-nmap" aria-label="Permalink to &quot;Ping Sweep - \`Nmap\`&quot;">​</a></h2><p>Bạn có thể thực hiện ping sweep trong Nmap bằng cách sử dụng chế độ quét ping (<code>-sP</code>) trên toàn bộ subnet.</p><p>Ping sweep trên Nmap sẽ quét tất cả các node trên subnet và bắt đầu hiển thị tất cả các host đang hoạt động, cùng với địa chỉ MAC và thông tin thiết bị tương ứng.</p><p>Mở một cửa sổ Terminal mới trên Kali Linux và gõ:</p><p><code>nmap -sP 10.0.2.1/24</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Nmap scan report for 10.0.2.1</span></span>
<span class="line"><span>Host is up (0.0011s latency).</span></span>
<span class="line"><span>MAC Address: 22:44:99:33:11:55 QEMU virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.2</span></span>
<span class="line"><span>Host is up (0.00084s latency).</span></span>
<span class="line"><span>MAC Address: 22:44:99:33:11:55 (QEMU virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.3</span></span>
<span class="line"><span>Host is up (0.00097s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.22</span></span>
<span class="line"><span>Host is up (0.00075s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.23</span></span>
<span class="line"><span>Host is up (0.00066s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.37</span></span>
<span class="line"><span>Host is up (0.00051s latency).</span></span>
<span class="line"><span>MAC Address: 11:22:33:44:55:66 (Oracle VirtualBox virtual NIC)</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.15</span></span>
<span class="line"><span>Host is up.</span></span>
<span class="line"><span>Nmap done: 256 IP addresses (7 hosts up) scanned in 2.29 seconds</span></span></code></pre></div><h2 id="ping-sweep-bash" tabindex="-1">Ping Sweep - <code>Bash</code> <a class="header-anchor" href="#ping-sweep-bash" aria-label="Permalink to &quot;Ping Sweep - \`Bash\`&quot;">​</a></h2><p>Tôi sẽ chỉ một cách khác để kiểm tra các host đang hoạt động trên subnet bằng một chút <strong>lập trình Bash</strong>. Bạn có thể bỏ qua phần tiếp theo nếu không quan tâm.</p><h3 id="_1-kiem-tra-lenh-one-liner-đe-chi-lay-đia-chi-ip" tabindex="-1">1. Kiểm tra lệnh one-liner để chỉ lấy địa chỉ IP <a class="header-anchor" href="#_1-kiem-tra-lenh-one-liner-đe-chi-lay-đia-chi-ip" aria-label="Permalink to &quot;1. Kiểm tra lệnh one-liner để chỉ lấy địa chỉ IP&quot;">​</a></h3><p>Đầu tiên, tôi sẽ sử dụng lệnh <code>ping</code> trên một phạm vi subnet nhất định, để kiểm tra xem các host có đang hoạt động hay không. <strong>Mục tiêu là: ping từng host trên một phạm vi nhất định với đầu ra sạch.</strong></p><p>Phần đầu ra sạch là vì khi chúng ta sử dụng lệnh <code>ping</code>, nó trả về một chuỗi các dòng, mục tiêu là loại bỏ tất cả thông tin không cần thiết và chỉ giữ lại địa chỉ IP. <strong>Ví dụ:</strong></p><p><code>ping -c 1 8.8.8.8</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PING 8.8.8.8 (8.8.8.8) 56(84) bytes of data.</span></span>
<span class="line"><span>64 bytes from 8.8.8.8: icmp_seq=2 ttl=54 time=155 ms</span></span>
<span class="line"><span>--- 8.8.8.8 ping statistics ---</span></span>
<span class="line"><span>1 packets transmitted, 0 received, 100% packet loss, time 0ms</span></span></code></pre></div><p>Chúng ta chỉ cần dòng thứ hai của đầu ra bắt đầu bằng <strong>&quot;64 bytes(...)&quot;</strong> chứa địa chỉ IP của host đang hoạt động.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>64 bytes from 8.8.8.8: icmp_seq=2 ttl=54 time=155 m</span></span></code></pre></div><p><strong>Chỉ lấy địa chỉ IP:</strong></p><p><code>ping -c 5 8.8.8.8 | grep &quot;64&quot; | cut -d &quot; &quot; -f 4 | tr -d &quot;:&quot; ; &gt; iptest.txt</code></p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">8.8.8.8</span></span></code></pre></div><p>Phân tích lệnh one-liner (theo pipe):</p><ol><li>Ping IP 5 lần;</li><li>Grep lấy các ký tự đầu dòng (<strong>64</strong> bytes...);</li><li>Cut các khoảng trắng thành 4 phần để lấy chuỗi IP;</li><li>Sử dụng lệnh translate để xóa ký tự &quot;:&quot;;</li><li>Xuất kết quả ra file .txt;</li></ol><h3 id="_2-chuyen-đoi-thanh-script" tabindex="-1">2. Chuyển đổi thành script <a class="header-anchor" href="#_2-chuyen-đoi-thanh-script" aria-label="Permalink to &quot;2. Chuyển đổi thành script&quot;">​</a></h3><ol><li>Tạo file .sh (pingsweep.sh)</li></ol><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/bin/bash </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ==</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">then</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[-] You forgot the IP address!&quot;</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;[-] Syntax: ./ipsweep.sh 10.10.10&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ip </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> \`</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">seq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 254</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">\`</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">do</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ping</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> $1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$ip </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;64 bytes&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot; &quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tr</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;:&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">done</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fi</span></span></code></pre></div><p>Sẽ tiện hơn khi lấy đầu vào của người dùng ở ba octet đầu và octet cuối là vòng lặp (1 - 254). <strong>Ví dụ đầu vào: 192.168.1</strong></p><p>Script dưới đây rất đơn giản, có một câu lệnh điều kiện để lấy đúng đầu vào của người dùng, một vòng lặp qua phạm vi subnet, và lệnh one-liner sử dụng đầu vào của người dùng với biến vòng lặp.</p><ol start="2"><li>Lưu file, thay đổi quyền và cấp quyền thực thi:</li></ol><p><code>chmod 770 pingsweep.sh</code><code>chmod +x pingsweep.sh</code></p><ol start="3"><li>Kiểm tra:</li></ol><p><code>./pingsweep.sh 10.0.2 &gt; ping-results.txt</code><code>cat ping-results.txt</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.0.2.3</span></span>
<span class="line"><span>10.0.2.1</span></span>
<span class="line"><span>10.0.2.15</span></span>
<span class="line"><span>10.0.2.22</span></span>
<span class="line"><span>10.0.2.23</span></span>
<span class="line"><span>10.0.2.37</span></span></code></pre></div><h2 id="thuc-hien-stealth-syn-scan" tabindex="-1">Thực hiện Stealth SYN Scan <a class="header-anchor" href="#thuc-hien-stealth-syn-scan" aria-label="Permalink to &quot;Thực hiện Stealth SYN Scan&quot;">​</a></h2><p>Bây giờ, chọn một địa chỉ IP từ kết quả và thực hiện <strong>stealth syn scan</strong> trên <strong>Nmap</strong>.</p><p><code>nmap -sS &lt;Target IP Address&gt;</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>...</span></span>
<span class="line"><span>Host is up (0.00092s latency).</span></span>
<span class="line"><span>Not shown: 977 closed ports</span></span>
<span class="line"><span>PORT      STATE SERVICE</span></span>
<span class="line"><span>53/tcp    open  domain</span></span>
<span class="line"><span>80/tcp    open  http</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec</span></span>
<span class="line"><span>135/tcp   open  msrpc</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap</span></span>
<span class="line"><span>443/tcp   open  https</span></span>
<span class="line"><span>...</span></span></code></pre></div><p>SYN scan là tùy chọn quét mặc định và phổ biến nhất với lý do chính đáng. Nó có thể được thực hiện nhanh chóng, quét hàng nghìn cổng mỗi second trên mạng nhanh mà không bị cản trở bởi firewall.</p><h2 id="stealth-syn-scan-voi-phat-hien-phien-ban-va-he-đieu-hanh" tabindex="-1">Stealth SYN Scan với Phát hiện Phiên bản và Hệ điều hành <a class="header-anchor" href="#stealth-syn-scan-voi-phat-hien-phien-ban-va-he-đieu-hanh" aria-label="Permalink to &quot;Stealth SYN Scan với Phát hiện Phiên bản và Hệ điều hành&quot;">​</a></h2><p>Phát hiện phiên bản thu thập thông tin về dịch vụ cụ thể đang chạy trên một cổng mở, bao gồm tên sản phẩm và số phiên bản. Thông tin này có thể rất quan trọng trong việc xác định điểm xâm nhập cho một cuộc tấn công.</p><p>Nmap sẽ thực hiện stealth scan với phát hiện phiên bản cùng với phát hiện hệ điều hành.</p><p><code>nmap -sSV -O &lt;Target IP Address&gt; -oN Enumeration.txt</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Host is up (0.0017s latency).</span></span>
<span class="line"><span>Not shown: 977 closed ports</span></span>
<span class="line"><span>PORT      STATE SERVICE            VERSION</span></span>
<span class="line"><span>53/tcp    open  domain?</span></span>
<span class="line"><span>80/tcp    open  http               Microsoft IIS httpd 8.5</span></span>
<span class="line"><span>88/tcp    open  kerberos-sec       Microsoft Windows Kerberos (server time: 2019-12-06 20:56:57Z)</span></span>
<span class="line"><span>135/tcp   open  msrpc              Microsoft Windows RPC</span></span>
<span class="line"><span>139/tcp   open  netbios-ssn        Microsoft Windows netbios-ssn</span></span>
<span class="line"><span>389/tcp   open  ldap               Microsoft Windows Active Directory LDAP (Domain: Lab.local, Site: Default-First-Site-Name)</span></span>
<span class="line"><span>443/tcp   open  ssl/https?</span></span></code></pre></div><p><code>-oN</code> có nghĩa là xuất kết quả vào file text sẽ được lưu trong thư mục home /root/ với tên <code>Enumeration.txt</code>.</p><hr><h3 id="ket-luan" tabindex="-1">Kết luận <a class="header-anchor" href="#ket-luan" aria-label="Permalink to &quot;Kết luận&quot;">​</a></h3><p>Bằng cách thực hiện enumerate dịch vụ, kẻ tấn công có thể cố gắng tìm các lỗ hổng liên quan đến ứng dụng cụ thể đó và khai thác chúng để chiếm quyền truy cập vào máy mục tiêu.</p>`,50)]))}const k=n(p,[["render",e]]);export{g as __pageData,k as default};
